<?php require_once '../config/database.php'; require_once '../config/helpers.php'; if(empty($_SESSION['admin'])){header('Location: login.php');exit;} $cats=$pdo->query('SELECT * FROM categories')->fetchAll(); $p=['id'=>'','category_id'=>'','name'=>'','slug'=>'','regular_price'=>'','sale_price'=>'','discount_percent'=>0,'material'=>'','color'=>'','size'=>'','image'=>'','hover_image'=>'','description'=>'','stock'=>50,'is_new'=>1,'is_featured'=>0]; if(!empty($_GET['id'])){$st=$pdo->prepare('SELECT * FROM products WHERE id=?');$st->execute([$_GET['id']]);$p=$st->fetch();}
if($_SERVER['REQUEST_METHOD']==='POST'){ if(!empty($_POST['id'])){$sql='UPDATE products SET category_id=?,name=?,slug=?,regular_price=?,sale_price=?,discount_percent=?,material=?,color=?,size=?,image=?,hover_image=?,description=?,stock=?,is_new=?,is_featured=? WHERE id=?';$pdo->prepare($sql)->execute([$_POST['category_id'],$_POST['name'],$_POST['slug'],$_POST['regular_price'],$_POST['sale_price']?:null,$_POST['discount_percent'],$_POST['material'],$_POST['color'],$_POST['size'],$_POST['image'],$_POST['hover_image'],$_POST['description'],$_POST['stock'],isset($_POST['is_new'])?1:0,isset($_POST['is_featured'])?1:0,$_POST['id']]);} else {$sql='INSERT INTO products(category_id,name,slug,regular_price,sale_price,discount_percent,material,color,size,image,hover_image,description,stock,is_new,is_featured) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)';$pdo->prepare($sql)->execute([$_POST['category_id'],$_POST['name'],$_POST['slug'],$_POST['regular_price'],$_POST['sale_price']?:null,$_POST['discount_percent'],$_POST['material'],$_POST['color'],$_POST['size'],$_POST['image'],$_POST['hover_image'],$_POST['description'],$_POST['stock'],isset($_POST['is_new'])?1:0,isset($_POST['is_featured'])?1:0]);} header('Location: index.php');exit;}
?>
<!doctype html><html lang="vi"><head><meta charset="utf-8"><link rel="stylesheet" href="../assets/css/style.css"><title>Sản phẩm</title></head><body><div class="admin-nav"><b>SUDES Admin</b><a href="index.php">Dashboard</a></div><main class="admin-container"><h1><?= $p['id']?'Sửa':'Thêm' ?> sản phẩm</h1><form class="form" method="post"><input type="hidden" name="id" value="<?=$p['id']?>"><select name="category_id"><?php foreach($cats as $c): ?><option value="<?=$c['id']?>" <?=$p['category_id']==$c['id']?'selected':''?>><?=$c['name']?></option><?php endforeach; ?></select><input name="name" value="<?=$p['name']?>" placeholder="Tên"><input name="slug" value="<?=$p['slug']?>" placeholder="slug"><input name="regular_price" value="<?=$p['regular_price']?>" placeholder="Giá gốc"><input name="sale_price" value="<?=$p['sale_price']?>" placeholder="Giá sale"><input name="discount_percent" value="<?=$p['discount_percent']?>" placeholder="% giảm"><input name="material" value="<?=$p['material']?>" placeholder="Chất liệu"><input name="color" value="<?=$p['color']?>" placeholder="Màu"><input name="size" value="<?=$p['size']?>" placeholder="Size"><input name="image" value="<?=$p['image']?>" placeholder="Link ảnh chính"><input name="hover_image" value="<?=$p['hover_image']?>" placeholder="Link ảnh hover"><textarea name="description" placeholder="Mô tả"><?=$p['description']?></textarea><input name="stock" value="<?=$p['stock']?>" placeholder="Tồn kho"><label><input type="checkbox" name="is_new" <?=$p['is_new']?'checked':''?>> Hàng mới</label><br><label><input type="checkbox" name="is_featured" <?=$p['is_featured']?'checked':''?>> Nổi bật</label><br><br><button class="btn">Lưu</button></form></main></body></html>
